import { callMcpSkill } from "@/lib/ai/skills/mcp";

export async function main() {
  const result = await callMcpSkill({
    toolId: "294100e8-c648-4e5f-a254-95a14b56e398",
    toolName: "compare_event_outcome_quotes",
    args: {
      eventQuery: "Paris Saint-Germain FC vs. Liverpool FC",
      outcomes: [
        "Will Paris Saint-Germain FC win on 2026-04-08?",
        "Will Paris Saint-Germain FC vs. Liverpool FC end in a draw?",
        "Will Liverpool FC win on 2026-04-08?"
      ],
      includeHistory: false
    }
  });

  const matched = Array.isArray(result?.matchedOutcomes) ? result.matchedOutcomes : [];

  const rows = matched.map((o) => ({
    matchedName: o.matchedName,
    currentPrice: o.currentPrice,
    impliedProbability: o.impliedProbability,
    bestBid: o.bestBid,
    bestAsk: o.bestAsk,
    spread: o.spread,
    spreadCentsDisplay: o.spreadCentsDisplay,
    spreadPercentDisplay: o.spreadPercentDisplay,
    readableQuote: o.readableQuote
  }));

  return {
    eventTitle: result?.eventTitle,
    eventSlug: result?.eventSlug,
    eventUrl: result?.eventUrl,
    fetchedAt: result?.fetchedAt,
    selectionReason: result?.selectionReason,
    unmatchedOutcomes: Array.isArray(result?.unmatchedOutcomes) ? result.unmatchedOutcomes : [],
    outcomes: rows
  };
}

