import { callMcpSkill } from "@/lib/ai/skills/mcp";

export async function main() {
  const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";

  const result = await callMcpSkill({
    toolId,
    toolName: "analyze_event_whale_breakdown",
    args: {
      marketQuery: "2026 FIFA World Cup Winner",
      maxOutcomes: 20
    }
  });

  const requested = ["Spain", "France", "England", "Switzerland", "New Zealand", "South Korea"];

  const whales = Array.isArray(result?.whalesByOutcome) ? result.whalesByOutcome : [];
  const matched = whales.filter((row) => requested.includes(row?.outcome));

  let strongest = null;
  for (const row of matched) {
    if (!strongest || (row.totalWhaleValue ?? 0) > (strongest.totalWhaleValue ?? 0)) {
      strongest = row;
    }
  }

  return {
    eventTitle: result?.eventTitle,
    topWhaleOutcome: result?.topWhaleOutcome,
    requestedOutcomes: requested,
    sampledMatches: matched.map((row) => ({
      rank: row.rank,
      outcome: row.outcome,
      whaleCount: row.whaleCount,
      totalWhaleValue: row.totalWhaleValue,
      currentPrice: row.currentPrice,
      convictionLevel: row.convictionLevel
    })),
    strongestWhaleBackingAmongRequested: strongest
      ? {
          outcome: strongest.outcome,
          totalWhaleValue: strongest.totalWhaleValue,
          whaleCount: strongest.whaleCount,
          currentPrice: strongest.currentPrice,
          convictionLevel: strongest.convictionLevel
        }
      : null,
    fetchedAt: result?.fetchedAt
  };
}

