import { pickTopSemanticCandidates } from "@/lib/ai/skills/semantic-targeting";

export async function main() {
  const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";

  const target = "Will Paris Saint-Germain FC win on 2026-04-08?";
  const discovery = await callMcpSkill({
    toolId,
    toolName: "search_markets",
    args: {
      query: target,
      status: "live",
      limit: 10
    }
  });

  const candidates = Array.isArray(discovery?.results) ? discovery.results : [];
  const ranked = pickTopSemanticCandidates({
    target,
    candidates,
    requiredTerms: ["Paris Saint-Germain FC"],
    avoidTerms: ["election", "politics", "government"],
    limit: 3
  });

  const picked = Array.isArray(ranked) && ranked.length > 0 ? ranked[0] : null;

  if (!picked || !picked.slug) {
    return {
      missingData: "Could not resolve a live market slug for the requested market.",
      attemptedBranches: ["search_markets", "semantic_targeting"],
      stopReason: "No suitable live market match returned from discovery."
    };
  }

  const event = await callMcpSkill({
    toolId,
    toolName: "get_event_by_slug",
    args: {
      slug: picked.slug
    }
  });

  const markets = Array.isArray(event?.markets) ? event.markets : [];
  const market = markets.find((m) => {
    const question = typeof m?.question === "string" ? m.question : "";
    return question.includes("Paris Saint-Germain FC") || question.includes("PSG");
  }) || markets[0] || null;

  const yesTokenId =
    market && Array.isArray(market.tokens)
      ? market.tokens.find((t) => t && t.outcome === "YES" && typeof t.token_id === "string")?.token_id
      : null;

  if (!yesTokenId) {
    return {
      market: picked.title,
      slug: picked.slug,
      missingData: "Could not find a YES tokenId in the resolved event markets.",
      attemptedBranches: ["search_markets", "semantic_targeting", "get_event_by_slug"],
      stopReason: "Resolved event but token lookup was unavailable."
    };
  }

  const params = await callMcpSkill({
    toolId,
    toolName: "get_market_parameters",
    args: {
      tokenId: yesTokenId
    }
  });

  return {
    market: picked.title,
    slug: picked.slug,
    tokenId: yesTokenId,
    tradingParameters: {
      tickSize: params?.tickSize ?? null,
      feeRateBps: params?.feeRateBps ?? null,
      minOrderSize: params?.minOrderSize ?? null,
      negRisk: params?.negRisk ?? null
    },
    fetchedAt: params?.fetchedAt ?? null
  };
}

